module serial2parallel
(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg dout_parallel,
    output reg dout_valid
);
    reg [3:0] cnt;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 4'd0;
            dout_valid <= 1'b0;
        end
        else if (din_valid) begin
            cnt <= cnt + 1;
            if (cnt == 4'd8) begin
                dout_parallel <= {din_serial, dout_parallel[7:1]};
                dout_valid <= 1'b1;
            end
            else if (cnt == 4'd9) begin
                dout_valid <= 1'b0;
            end
        end
    end
endmodule

module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);
// DEFINE STATE PARAMETERS
parameter IDLE = 3'd0;
parameter SUB = 3'd1;
parameter mux_sel_0 = 3'd2;
parameter mux_sel_1 = 3'd3;
parameter shift = 3'd4;
parameter check_cnt = 3'd5;
parameter finish = 3'd6;
// DEFINE INTERNAL REGISTERS
reg [2:0] next_state, state;
reg [4:0] cnt;
reg [16:0] neg_divisor;
reg [16:0] sr;
reg [16:0] sub_result;
reg [16:0] mux_sel;
reg [16:0] carry_out;
// DEFINE COMBINATIONAL LOGIC
assign mux_sel_0 = (sr[16] == 1'b0) ? 1'b1 : 1'b0;
assign mux_sel_1 = (sr[16] == 1'b1) ? 1'b1 : 1'b0;
// DEFINE SEQUENTIAL LOGIC
always @(posedge clk or posedge rst) begin
    if (rst) begin
        state <= IDLE;
        cnt <= 5'b0;
        neg_divisor <= 17'b0;
        sr <= 17'b0;
    end else begin
        state <= next_state;
        if (state == IDLE) begin
            if (opn_valid == 1'b1) begin
                if (sign == 1'b1) begin
                    sr <= {1'b0, dividend, 8'b0};
                    neg_divisor <= {1'b0, ~divisor + 1'b1, 8'b0};
                end else begin
                    sr <= {1'b0, dividend, 8'b0};
                    neg_divisor <= {1'b0, divisor, 8'b0};
                end
                cnt <= 5'd1;
            end
        end else if (state == shift) begin
            sr <= {sr[15:0], carry_out[0]};
            cnt <= cnt + 5'd1;
        end else if (state == finish) begin
            cnt <= 5'b0;
            if (sign == 1'b1) begin
                sr <= {1'b0, sr[15:0]};
            end else begin
                sr <= sr;
            end
        end
    end
end
always @(*) begin
    case (state)
        IDLE: begin
            if (opn_valid == 1'b1) begin
                next_state = SUB;
            end else begin
                next_state = IDLE;
            end
        end
        SUB: begin
            sub_result = sr - neg_divisor;
            carry_out = sub_result[16] ? sr - neg_divisor + 17'b1 : sr - neg_divisor;
            next_state = mux_sel;
        end
        mux_sel_0: begin
            if (carry_out[16] == 1'b1) begin
                next_state = shift;
            end else begin
                next_state = check_cnt;
            end
        end
        mux_sel_1: begin
            if (carry_out[16] == 1'b1) begin
                next_state = shift;
            end else begin
                next_state = check_cnt;
            end
        end
        shift: begin
            next_state = check_cnt;
        end
        check_cnt: begin
            if (cnt[4] == 1'b1) begin
                next_state = finish;
            end else begin
                next_state = SUB;
            end
        end
        finish: begin
            if (res_valid == 1'b1) begin
                next_state = IDLE;
            end else begin
                next_state = finish;
            end
        end
        default: begin
            next_state = IDLE;
        end
    endcase
end
always @(posedge clk or posedge rst) begin
    if (rst) begin
        res_valid <= 1'b0;
    end else begin
        if (cnt[4] == 1'b1) begin
            res_valid <= 1'b1;
        end else begin
            if (res_valid == 1'b1) begin
                res_valid <= 1'b0;
            end else begin
                res_valid <= res_valid;
            end
        end
    end
end
always @(posedge clk or posedge rst) begin
    if (rst) begin
        result <= 16'b0;
    end else begin
        if (cnt[4] == 1'b1) begin
            result <= {sr[15:0], sr[16]};
        end else begin
            result <= result;
        end
    end
end
endmodule

module width_8to16
(
    input clk,
    input rst_n,
    input valid_in,
    input [7:0] data_in,
    output valid_out,
    output reg [15:0] data_out
);

reg [7:0] data_lock;
reg flag;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data_out <= 16'b0;
        data_lock <= 8'b0;
        flag <= 1'b0;
    end
    else if (valid_in) begin
        if (flag) begin
            data_out <= {data_lock, data_in};
            flag <= 1'b0;
        end
        else begin
            data_lock <= data_in;
            flag <= 1'b1;
        end
    end
    else begin
        flag <= 1'b0;
    end
end

assign valid_out = flag;

endmodule

module pe
(
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output [31:0] c
);
reg [31:0] c_reg;
always @(posedge clk or posedge rst) begin
    if (rst) begin
        c_reg <= 32'd0;
    end else begin
        c_reg <= c_reg + (a * b);
    end
end
assign c = c_reg;
endmodule

module traffic_light
(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output reg red
);
parameter idle = 2'b00;
parameter s1_red = 2'b01;
parameter s2_yellow = 2'b10;
parameter s3_green = 2'b11;
reg [7:0] cnt;
reg [1:0] state;
reg p_red, p_yellow, p_green;
always @(*) begin
    case (state)
        idle: begin
            p_red = 0;
            p_yellow = 0;
            p_green = 0;
            state = s1_red;
        end
        s1_red: begin
            p_red = 1;
            if (cnt == 3) begin
                state = s3_green;
                p_red = 0;
            end
        end
        s2_yellow: begin
            p_yellow = 1;
            if (cnt == 3) begin
                state = s1_red;
                p_yellow = 0;
            end
        end
        s3_green: begin
            p_green = 1;
            if (cnt == 3) begin
                state = s2_yellow;
                p_green = 0;
            end
        end
    endcase
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) cnt <= 8'd10;
    else begin
        if (pass_request && green) cnt <= 8'd10;
        else begin
            if (!green && p_green) cnt <= 8'd60;
            else begin
                if (!yellow && p_yellow) cnt <= 8'd5;
                else begin
                    if (!red && p_red) cnt <= 8'd10;
                end
            end
        end
    end
end
assign clock = cnt;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        red <= 0;
        yellow <= 0;
        green <= 0;
    end
    else begin
        if (!red && p_red) red <= 1;
        else begin
            if (!yellow && p_yellow) yellow <= 1;
            else begin
                if (!green && p_green) green <= 1;
            end
        end
    end
end
endmodule

module multi_16bit
(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output yout,
    output done
);
reg [31:0] yout_r;
reg [15:0] areg, breg;
reg [4:0] i;
reg done_r;
assign yout = yout_r;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) i <= 5'd0;
    else if(start && i<5'd17) i<= i+1;
    else i<=5'd0;
end
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) done_r <= 1'b0;
    else if(i==5'd16) done_r <= 1'b1;
    else if(i==5'd17) done_r <= 1'b0;
end
assign done = done_r;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        areg <= 16'b0;
        breg <= 16'b0;
        yout_r <= 32'b0;
    end
    else if(start) begin
        if(i==5'd0) begin
            areg <= ain;
            breg <= bin;
        end
        else if(i>5'd0 && i<5'd17) begin
            if(areg[i-1]) yout_r <= (yout_r + (breg << (i-1))) ;
        end
    end
end
endmodule

module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output mul_en_out,
    output mul_out
);
reg [7:0] mul_a_reg, mul_b_reg;
reg [15:0] partial_products [7:0];
reg [15:0] sum [7:0];
reg [2:0] stage;
reg mul_en_out_reg;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_a_reg <= 8'b0;
        mul_b_reg <= 8'b0;
        mul_en_out_reg <= 1'b0;
        stage <= 3'b0;
        for (int i = 0; i < 8; i++) begin
            partial_products[i] <= 16'b0;
            sum[i] <= 16'b0;
        end
    end
    else begin
        if (mul_en_in) begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
            mul_en_out_reg <= 1'b1;
        end
        else begin
            mul_en_out_reg <= 1'b0;
        end
        if (mul_en_out_reg) begin
            for (int i = 0; i < 8; i++) begin
                partial_products[i] <= mul_a_reg[i] ? {8'b0, mul_b_reg} << i : 16'b0;
            end
            stage <= 3'b100;
        end
        else begin
            stage <= 3'b000;
        end
        for (int i = 0; i < 8; i++) begin
            if (stage == 3'b100) begin
                sum[i] <= partial_products[i];
            end
            else if (stage == 3'b101) begin
                sum[i] <= sum[i] + partial_products[i];
            end
            else if (stage == 3'b110) begin
                sum[i] <= sum[i] + partial_products[i];
            end
            else if (stage == 3'b111) begin
                sum[i] <= sum[i] + partial_products[i];
            end
        end
        stage <= stage + 1;
    end
end
assign mul_en_out = mul_en_out_reg;
assign mul_out = sum[7];
endmodule

module parallel2serial
(
    input clk,
    input rst_n,
    input [3:0] d,
    output valid_out,
    output dout
);

reg [2:0] cnt;
reg valid;
reg [3:0] data;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 3'b0;
        valid <= 1'b0;
        data <= 4'b0;
    end
    else begin
        if (cnt == 3'b11) begin
            data <= d;
            cnt <= 3'b0;
            valid <= 1'b1;
        end
        else begin
            cnt <= cnt + 1'b1;
            valid <= 1'b0;
            data <= {data[2:0], data[3]};
        end
    end
end

assign dout = data[3];
assign valid_out = valid;

endmodule

module div_16bit
(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);
    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] remainder;
    reg [15:0] quotient;
    integer i;

    always @(A or B) begin
        dividend <= A;
        divisor <= B;
    end

    always @(dividend or divisor) begin
        result <= 0;
        odd <= 0;
        remainder <= dividend;

        for (i = 0; i < 16; i = i + 1) begin
            if (remainder[15:8] >= divisor) begin
                remainder[15:8] = remainder[15:8] - divisor;
                remainder = {remainder[14:0], 1'b1};
            end
            else begin
                remainder = {remainder[14:0], 1'b0};
            end
        end

        result <= remainder[15:0];
        odd <= remainder[15:0];
    end
endmodule

module multi_8bit
(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);
parameter BIT_WIDTH = 8;
parameter PRODUCT_WIDTH = 16;
reg [7:0] A_shifted;
reg [3:0] i;
always @(*) begin
    // Initialize product to 0
    product = 0;
    // Iterate through each bit of the multiplier
    for (i = 0; i < BIT_WIDTH; i = i + 1) begin
        // Check if the current bit of the multiplier is set
        if (B[i] == 1) begin
            // Condition met: Add the shifted multiplicand to the product
            product = product + (A << i);
        end
        // Shift the multiplicand by one bit
        A_shifted = A << 1;
    end
end
endmodule

module freq_div
(
    input CLK_in,
    input RST,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1
);
reg [3:0] cnt_10;
reg [6:0] cnt_100;
always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
        CLK_50 <= 1'b0;
        CLK_10 <= 1'b0;
        CLK_1 <= 1'b0;
        cnt_10 <= 4'b0;
        cnt_100 <= 7'b0;
    end
    else begin
        // CLK_50 generation
        CLK_50 <= ~CLK_50;

        // CLK_10 generation
        if (cnt_10 == 4'd4) begin
            CLK_10 <= ~CLK_10;
            cnt_10 <= 4'b0;
        end
        else begin
            cnt_10 <= cnt_10 + 4'b1;
        end

        // CLK_1 generation
        if (cnt_100 == 7'd49) begin
            CLK_1 <= ~CLK_1;
            cnt_100 <= 7'b0;
        end
        else begin
            cnt_100 <= cnt_100 + 7'b1;
        end
    end
end
endmodule

module alu
(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);
    parameter ADD = 6'b100000;
    parameter ADDU = 6'b100001;
    parameter SUB = 6'b100010;
    parameter SUBU = 6'b100011;
    parameter AND = 6'b100100;
    parameter OR = 6'b100101;
    parameter XOR = 6'b100110;
    parameter NOR = 6'b100111;
    parameter SLT = 6'b101010;
    parameter SLTU = 6'b101011;
    parameter SLL = 6'b000000;
    parameter SRL = 6'b000010;
    parameter SRA = 6'b000011;
    parameter SLLV = 6'b000100;
    parameter SRLV = 6'b000110;
    parameter SRAV = 6'b000111;
    parameter LUI = 6'b001111;
    wire signed [31:0] a_signed = a;
    wire signed [31:0] b_signed = b;
    reg [31:0] res;
    reg [32:0] res_signed;
    assign r = res;
    assign zero = res == 0;
    assign carry = res[32];
    assign negative = res_signed[31];
    assign overflow = res_signed[32] ^ res_signed[31];
    assign flag = (aluc == SLT || aluc == SLTU) ? res[0] : 1'bz;
    always @(*) begin
        case (aluc)
            ADD: res = a_signed + b_signed;
            ADDU: res = a + b;
            SUB: res = a_signed - b_signed;
            SUBU: res = a - b;
            AND: res = a & b;
            OR: res = a | b;
            XOR: res = a ^ b;
            NOR: res = ~(a | b);
            SLT: res = a_signed < b_signed;
            SLTU: res = a < b;
            SLL: res = b << a[4:0];
            SRL: res = b >> a[4:0];
            SRA: res = b_signed >>> a[4:0];
            SLLV: res = b << a[4:0];
            SRLV: res = b >> a[4:0];
            SRAV: res = b_signed >>> a[4:0];
            LUI: res = {b[15:0], 16'b0};
        endcase
    end
endmodule

module edge_detect
(
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);

    reg a_prev;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            a_prev <= 1'b0;
            rise <= 1'b0;
            down <= 1'b0;
        end else begin
            a_prev <= a;
            rise <= 1'b0;
            down <= 1'b0;

            if (a_prev == 1'b0 && a == 1'b1) begin
                rise <= 1'b1;
            end else if (a_prev == 1'b1 && a == 1'b0) begin
                down <= 1'b1;
            end
        end
    end

endmodule

