module multi_pipe_4bit
#(
    parameter size = 4
)
(
    input clk,
    input rst_n,
    input mul_a,
    input mul_b,
    output reg mul_out
);
    parameter size = 4;
    reg [3:0] reg_a, reg_b;
    reg [7:0] reg_s [size-1:0];
    reg [7:0] reg_c [size-1:0];
    reg [7:0] reg_p;
    // Extend input signals
    always @(*) begin
        reg_a = {size{1'b0}};
        reg_b = {size{1'b0}};
        reg_a[size-1:0] = mul_a;
        reg_b[size-1:0] = mul_b;
    end
    // Multiplier
    genvar i;
    generate
        for (i = 0; i < size; i = i + 1) begin : mul_block
            wire [7:0] pp;
            assign pp = reg_b[i] ? (reg_a << i) : 'd0;
            always @(posedge clk or negedge rst_n) begin
                if (!rst_n) begin
                    reg_s[i] <= 'd0;
                    reg_c[i] <= 'd0;
                end else begin
                    reg_s[i] <= pp;
                    reg_c[i] <= reg_c[i-1];
                end
            end
        end
    endgenerate
    // Adder
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            reg_p <= 'd0;
        end else begin
            reg_p <= reg_c[size-1];
        end
    end
    // Final product calculation
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_out <= 'd0;
        end else begin
            mul_out <= reg_p + reg_s[size-1];
        end
    end
endmodule

module calendar
(
    input CLK,
    input RST,
    output reg [5:0] Hours,
    output reg [5:0] Mins,
    output reg [5:0] Secs
);
    always @(posedge CLK or posedge RST) begin
        if (RST)
            Secs <= 6'd0;
        else if (Secs == 6'd59)
            Secs <= 6'd0;
        else
            Secs <= Secs + 1;
    end
    always @(posedge CLK or posedge RST) begin
        if (RST)
            Mins <= 6'd0;
        else if (Mins == 6'd59 && Secs == 6'd59)
            Mins <= 6'd0;
        else if (Secs == 6'd59)
            Mins <= Mins + 1;
        else
            Mins <= Mins;
    end
    always @(posedge CLK or posedge RST) begin
        if (RST)
            Hours <= 6'd0;
        else if (Hours == 6'd23 && Mins == 6'd59 && Secs == 6'd59)
            Hours <= 6'd0;
        else if (Mins == 6'd59 && Secs == 6'd59)
            Hours <= Hours + 1;
        else
            Hours <= Hours;
    end
endmodule

module adder_32bit
(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

wire [32:0] carry;
assign carry[0] = 1'b0;

genvar i;
generate
    for (i = 0; i < 32; i = i + 1) begin
        assign {carry[i+1], S[i+1]} = A[i+1] + B[i+1] + carry[i];
    end
endgenerate

assign C32 = carry[32];

endmodule

